mapper.select:
SELECT INPUT_NO, ITEM_NO, ITEM_NAME, ITEM_ID, ORDERNO, IS_USE, ITEM_TYPE, ACTIVITY, CPNY_ID
  FROM PA_ITEM_INPUT
 WHERE CPNY_ID  = #{cpnyId, jdbcType=VARCHAR}
   AND ACTIVITY = 1

   AND IS_USE   = #{isUse, jdbcType=NUMERIC}


   AND ITEM_TYPE = #{itemType, jdbcType=NUMERIC}

 ORDER BY ORDERNO, INPUT_NO

mapper.delete:
DELETE FROM PA_ITEM_INPUT
 WHERE CPNY_ID   = #{cpnyId,   jdbcType=VARCHAR}
   AND IS_USE    = #{isUse,    jdbcType=NUMERIC}
   AND ITEM_TYPE = #{itemType, jdbcType=NUMERIC}

