SELECT S.*,
       E.LOCAL_NAME      AS LOCAL_NAME_EMP,
       HD.ORG_NAME_LOCAL AS DEPT_NAME_VAL
  FROM PA_SUMMARY_HTSV S
  LEFT JOIN HR_EMPLOYEE   E  ON S.EMPID   = E.EMPID
                            AND E.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
  LEFT JOIN HR_DEPARTMENT HD ON E.DEPTNO  = HD.DEPTNO
 WHERE S.CPNY_ID         = #{cpnyId, jdbcType=VARCHAR}
   AND S.PAY_SCHEDULE_NO = #{payScheduleNo, jdbcType=VARCHAR}

   AND E.DEPTNO IN

           #{d, jdbcType=VARCHAR}


 ORDER BY S.EMPID
